module RefModule (
    input [3:0] x0, // current input
    input [3:0] x1, // previous input
    input [3:0] x2, // two samples ago
    input [3:0] x3, // three samples ago
    output [4:0] y   // output (5 bits to accommodate possible overflow)
);
    // Coefficients
    parameter C0 = 1;
    parameter C1 = 2;
    parameter C2 = 1;
    parameter C3 = 0;

      wire _n01 = (C0 * x0) + (C1 * x1) + (C2 * x2)[0] ^ (C3 * x3)[0];
  wire _c01 = (C0 * x0) + (C1 * x1) + (C2 * x2)[0] & (C3 * x3)[0];
  wire _n02 = (C0 * x0) + (C1 * x1) + (C2 * x2)[1] ^ (C3 * x3)[1] ^ _c01;
  wire _c02 = ((C0 * x0) + (C1 * x1) + (C2 * x2)[1] & (C3 * x3)[1]) | ((C0 * x0) + (C1 * x1) + (C2 * x2)[1] & _c01) | ((C3 * x3)[1] & _c01);
  wire _n03 = (C0 * x0) + (C1 * x1) + (C2 * x2)[2] ^ (C3 * x3)[2] ^ _c02;
  wire _c03 = ((C0 * x0) + (C1 * x1) + (C2 * x2)[2] & (C3 * x3)[2]) | ((C0 * x0) + (C1 * x1) + (C2 * x2)[2] & _c02) | ((C3 * x3)[2] & _c02);
  wire _n04 = (C0 * x0) + (C1 * x1) + (C2 * x2)[3] ^ (C3 * x3)[3] ^ _c03;
  wire _c04 = ((C0 * x0) + (C1 * x1) + (C2 * x2)[3] & (C3 * x3)[3]) | ((C0 * x0) + (C1 * x1) + (C2 * x2)[3] & _c03) | ((C3 * x3)[3] & _c03);
  assign y = {_n01, _n02, _n03, _n04};
endmodule
